        logits, sampling_params, is_for_speculation, is_for_context_encoding
    )
else:
    res = logits

# A hack to ensure active_block_table and attention_mask is not optimized away
# if not None for prefix caching flow.

if self.is_prefix_caching:
    if active_block_table is not None and len(active_block_table.shape) == 1:
        res = res + active_block_table[0] * 0
    if attention_mask is not None and self.prefix_size == 0:
        res = res + attention_mask[0] * 0

outputs = [res]

if self.neuron_config.output_logits:
    logits = _gather_along_dim(
        logits,
        partition_dim=2,
        process_group=get_tp_group(self.config),
    )
    outputs += [logits]

# Add captured tensors if tensor capture is enabled
if self.neuron_config.tensor_capture_config:
    captured_tensors = self._get_captured_tensors(outputs[0].device)
    outputs += captured_tensors

outputs += updated_kv_cache

if self.neuron_config.enable_eagle_speculation:
    if is_for_context_encoding:
        outputs = outputs + [hidden_states] + [self.full_hidden_states]
    else:
        outputs = outputs + [self.full_hidden_states]
if self.neuron_config.lora_config is not None:
    outputs += lora_weights

def _get_constructed_outputs(self, outputs, is_run_on_neuron):
    # Process outputs
    if self.on_device_sampling and self.neuron_config.output_logits and not \
            (self.neuron_config.enable_fused_speculation or self.neuron_config.is_medusa):
        logits_or_next_tokens = outputs[:2]
        constructed_outputs = self._construct_output_with_tokens_and_logits(next_tokens=logits_or_next_tokens[0], logits=logits_or_next_tokens[1])
        captured_tensors_offset = self._get_captured_tensors_offset()
        if captured_tensors_offset > 0:
            constructed_outputs.captured_tensors = outputs[2: 2 + captured_tensors_offset]
    else:
        if is_run_on_neuron:
            # When run on neuron, KV cache remains on device
            logits_or_next_tokens = outputs
        else:
            # When run on cpu, KV cache is returned which has to be ignored
            logits_or_next_tokens, *_ = outputs
        constructed_outputs = self._construct_output(logits_or_next_tokens)
    return constructed_outputs

def _get_captured_tensors_offset(self):
    if self.neuron_config.tensor_capture_config:
        return self.neuron_config.tensor_capture_config.get_offset()
    return 0

def _construct_output_with_tokens_and_logits(self, next_tokens, logits, hidden_states=[]):
    OutputParams = CausalLMOutputWithPast(
        logits=logits,
        hidden_states=hidden_states,
        attentions=None,
    )
    OutputParams.tokens = next_tokens
    # Initialize captured_tensors attribute
    OutputParams.captured_tensors = None
    return OutputParams

def _construct_output(self, logits_or_next_tokens):
    if self.neuron_config.is_medusa:
        next_tokens = logits_or_next_tokens[:1, :, :]
    else:
        if (
            self.async_mode
            and not self.neuron_config.enable_fused_speculation
            and isinstance(logits_or_next_tokens, list)
        ):
            logits_or_next_tokens = logits_or_next_tokens[0]
        next_tokens = logits_or_next_tokens

    OutputParams = CausalLMOutputWithPast(
        logits=None if self.on_device_sampling else logits_or_next_tokens,
        hidden_states=logits_or_next_tokens,
        attentions=None,
    )

    if self.neuron_config.is_medusa:
        OutputParams.tokens = next_tokens[:1, :, :]
        OutputParams.medusa_tokens = next_tokens[1:, :, :]
    elif self.neuron_config.enable_fused_speculation:
        OutputParams.fused_outputs = next_tokens
        OutputParams.async_should_stop = self.async_should_stop
    else:
        OutputParams.tokens = next_tokens

    # Initialize captured_tensors attribute
    OutputParams.captured_tensors = None

    return OutputParams

def _prepare_inputs(self):
    accepted_indices = torch.zeros(
        (self.neuron_config.batch_size, self.neuron_config.num_medusa_heads + 1),
        dtype=torch.int32,
    )
    current_length = torch.zeros(
        (self.neuron_config.batch_size, self.neuron_config.num_medusa_heads + 1),
        dtype=torch.int32,
    )
    medusa_mask = torch.zeros(
        (
            self.neuron_config.batch_size,
            self.neuron_config.medusa_speculation_length,

    if not self.is_chunked_prefill:
        if input_ids.shape[0] != sampling_params.shape[0]:
            sampling_params = sampling_params[: input_ids.shape[0]]

    return sampling_params

def take_draft_token_ids(self) -> DraftTokenIds | None:
    if self._draft_token_ids is None:
        return None
    req_ids = self.input_batch.req_ids
    draft_token_ids = self._draft_token_ids
    self._draft_token_ids = None
    return DraftTokenIds(req_ids, draft_token_ids)

def _dummy_run(self, num_tokens: int, uniform_decode: bool = False) -> None:
    """Execute a dummy forward pass for engine initialization and warmup."""
    if self.model is None:
        logger.warning("Model is not loaded, skipping dummy run")
        return

    try:
        # Create minimal dummy input
        dummy_input = ModelInputForNeuron(
            request_ids=["dummy_request"],
            input_tokens=torch.ones(
                (1, num_tokens), dtype=torch.long, device=self.device
            ),
            position_ids=torch.arange(
                num_tokens, dtype=torch.long, device=self.device
            ).unsqueeze(0),
            input_block_ids=torch.zeros(1, dtype=torch.long, device=self.device),
            slot_mapping=torch.arange(
                num_tokens, dtype=torch.long, device=self.device
            ),
            block_tables=torch.arange(
                (num_tokens + self.block_size - 1) // self.block_size,
                dtype=torch.long,
                device=self.device,
            ).unsqueeze(0),
            full_context_lens=torch.tensor(
                [num_tokens], dtype=torch.long, device=self.device
            ).reshape(-1, 1),
            computed_context_lens=torch.tensor(
                [num_tokens - 1], dtype=torch.long, device=self.device
            ).reshape(-1, 1),
            sampling_params=self.get_nxd_sampling_params(
                torch.ones((1, num_tokens), dtype=torch.long, device=self.device)
            ),
            multi_modal_kwargs=None,
            adapter_ids=None,
            prefill_completion_state=None,
        )

        # Execute dummy forward pass
        if self.model.architecture in NEURON_MULTI_MODAL_MODELS:
            self._execute_model_for_multimodal_models(dummy_input)
        else:
            self._execute_model_for_text(dummy_input)

    except Exception as e:
        logger.warning(
            "Dummy run failed: %s. This may be expected during initialization.", e
        )

    lora_serving_config: LoraServingConfig,
    speculative_config: SpeculativeConfig | None,
):
    on_device_sampling_config = OnDeviceSamplingConfig(
        dynamic=True, deterministic=False
    )

    if scheduler_config.enable_chunked_prefill:
        batch_size = 1
        max_context_length = scheduler_config.max_num_batched_tokens
    else:
        batch_size = scheduler_config.max_num_seqs
        max_context_length = model_config.max_model_len

    default_num_blocks = (
        ceil(model_config.max_model_len // cache_config.block_size)
        * scheduler_config.max_num_seqs
    )
    if cache_config.num_gpu_blocks_override is not None:
        default_num_blocks = cache_config.num_gpu_blocks_override

def forward(self, input_ids, input_block_ids, **kwargs):
    forward_start = time.perf_counter()
    batch_size = (
        input_ids.shape[0]
        if isinstance(input_ids, torch.Tensor)
        else len(input_ids)
    )

    with self._reordered(input_block_ids, input_ids=input_ids, **kwargs) as (
        sorted_ids,
        inputs,
        restore,
    ):
        # Time model execution
        model_start = time.perf_counter()
        output = self.model(
            inputs["input_ids"],
            attention_mask=None,
            seq_ids=sorted_ids,
            block_table=inputs["block_tables"],
            **{
                k: v
                for k, v in inputs.items()
                if k
                not in ["input_ids", "block_tables", "prefill_completion_state"]
            },
        )
        model_elapsed = (time.perf_counter() - model_start) * 1000
        logger.debug("[PERF]     model_execution: %.2fms", model_elapsed)

        # Time output processing
        output_proc_start = time.perf_counter()
        if self.model.config.neuron_config.on_device_sampling_config:
            output = output.hidden_states
            if getattr(
                self.model.config.neuron_config, "enable_fused_speculation", False
            ):
                fused = output
                output = self._remask_fused_spec_output(fused, inputs)
        else:
            if self.neuron_config.is_chunked_prefill:
                assert kwargs.get("prefill_completion_state") is not None
                idx_for_sampling = (
                    kwargs["prefill_completion_state"].nonzero().flatten()
                )
                output = output.logits[0, idx_for_sampling, :]
            else:
                output = output.logits[:, -1, :]
        output_proc_elapsed = (time.perf_counter() - output_proc_start) * 1000
        logger.debug("[PERF]     output_processing: %.2fms", output_proc_elapsed)
